    public static void main(String[] args) throws FileNotFoundException, IOException {
        if (args.length != 1) {
            System.err.println("Usage: java -jar transformer.jar <source-directory>");
            System.exit(1);
        }

        String sourceDir = args[0];
        Path sourcePath = Paths.get(sourceDir);

        // Find all Java files in the source directory
        Files.walkFileTree(sourcePath, new java.nio.file.SimpleFileVisitor<Path>() {
            @Override
            public java.nio.file.FileVisitResult visitFile(Path file, java.nio.file.BasicFileAttributes attrs) throws IOException {
                if (file.toString().endsWith(".java")) {
                    processFile(file);
                }
                return java.nio.file.FileVisitResult.CONTINUE;
            }
        });
